const message = $json;

function findAttachments(part, results = []) {
  if (!part) return results;

  if (part.filename && part.body && part.body.attachmentId) {
    results.push({
      filename: part.filename,
      mimeType: part.mimeType,
      attachmentId: part.body.attachmentId,
      size: part.body.size || null,
      messageId: message.id,
      threadId: message.threadId,
      snippet: message.snippet || ""
    });
  }

  if (part.parts && Array.isArray(part.parts)) {
    for (const child of part.parts) {
      findAttachments(child, results);
    }
  }

  return results;
}

const attachments = findAttachments(message.payload);

if (attachments.length === 0) {
  return [{
    json: {
      messageId: message.id,
      foundAttachments: false,
      note: "No readable attachment metadata found in this Gmail message."
    }
  }];
}

return attachments.map(a => ({ json: a }));

// Safe final return for attachment helper.
// Handles:
// 1. No attachment found
// 2. PDF text extraction
// 3. CSV extraction rows
// 4. Metadata-only fallback

const MAX_CHARS = 6000;
const item = $json || {};
const allItems = $input.all();

// Case 1: no attachment found
if (item.foundAttachments === false) {
  return [{
    json: {
      success: false,
      foundAttachments: false,
      messageId: item.messageId || item.message_id || "[unknown]",
      note: item.note || "No readable attachment metadata found in this Gmail message."
    }
  }];
}

// Pull attachment metadata from Find Attachments
let meta = {};
try {
  const findItems = $items("Find Attachments");
  if (findItems && findItems[0] && findItems[0].json) {
    meta = findItems[0].json;
  }
} catch (e) {
  meta = {};
}

// Try to collect extracted content
let extractedText = "";

// CSV extraction often returns multiple rows as multiple items
if (allItems.length > 1) {
  extractedText = JSON.stringify(allItems.map(i => i.json), null, 2);
} else if (typeof item.text === "string") {
  extractedText = item.text;
} else if (typeof item.data === "string") {
  extractedText = item.data;
} else if (typeof item.attachmentText === "string") {
  extractedText = item.attachmentText;
} else if (typeof item.content === "string") {
  extractedText = item.content;
} else if (typeof item.extractedText === "string") {
  extractedText = item.extractedText;
} else if (Object.keys(item).length > 0) {
  extractedText = JSON.stringify(item, null, 2);
}

const cleanedText = String(extractedText || "")
  .replace(/\r/g, "")
  .replace(/\n{3,}/g, "\n\n")
  .trim();

const wasTruncated = cleanedText.length > MAX_CHARS;
const previewText = wasTruncated
  ? cleanedText.slice(0, MAX_CHARS) + "\n\n[TRUNCATED: attachment was longer than the safe preview limit.]"
  : cleanedText;

return [{
  json: {
    success: true,
    foundAttachments: true,
    filename: meta.filename || item.filename || item.fileName || "[unknown filename]",
    mimeType: meta.mimeType || item.mimeType || item.mime || "[unknown mime type]",
    messageId: meta.messageId || item.messageId || item.message_id || "[unknown message ID]",
    attachmentId: meta.attachmentId || item.attachmentId || item.attachment_id || "[unknown attachment ID]",
    attachmentCharacterCount: cleanedText.length,
    attachmentWasTruncated: wasTruncated,
    attachmentText: previewText || "[No readable text extracted.]",
    note: previewText
      ? "Attachment was processed and readable text/data was returned."
      : "Attachment was processed, but no readable text/data was extracted."
  }
}];

const base64url = $json.data;

if (!base64url) {
  return [{
    json: {
      success: false,
      error: "No attachment data found."
    }
  }];
}

const base64 = base64url
  .replace(/-/g, '+')
  .replace(/_/g, '/');

const buffer = Buffer.from(base64, 'base64');

const meta = $items("Find Attachments")[0].json;

return [{
  json: {
    success: true,
    filename: meta.filename || "attachment",
    mimeType: meta.mimeType || "application/octet-stream",
    messageId: meta.messageId,
    attachmentId: meta.attachmentId
  },
  binary: {
    data: {
      data: buffer.toString('base64'),
      mimeType: meta.mimeType || "application/octet-stream",
      fileName: meta.filename || "attachment"
    }
  }
}];
